FROM jsonb_to_recordset('[{"id": "cap-105-english-reading-passage-16", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-105-english-reading", "question_type": "reading_passage", "question_text": "(16-17)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Our Pinky Street, one of the oldest streets in the world, was almost lost to\na big fire last night. Most of the old houses on Pinky were burned down. The\nliving history we are proud of is dying. But we should never give up. Pinky is\nlike a parent, always there caring for our town. Now we must do something\ntogether to get the old Pinky back. There will be a meeting at 2:00 this Saturday\nafternoon at Town Office. Anyone who wants to help is welcome. Let’s see what\nwe can do.\nAdam Bolton, Town Office\nMarch 9", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "8d9695f6f61b", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": null, "intro_line": "(16-17)", "child_qnums": [16, 17]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-105-english-reading-passage-18", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-105-english-reading", "question_type": "reading_passage", "question_text": "(18-20)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "No idea where to spend your vacation? If you are a big fan of sun, beach,\nand water sports, then you must join FunGana 2016!\nOver the years, FunGana has taken people to many places in Gana.\nThis year, we are taking you to Piso Island, one of Gana’s beautiful islands.\nPiso Island is adjacent to Wako Island, the biggest island in Gana, so it is\nonly 15 minutes away by boat from Wako Island. The best time to visit?\nAll year around, the weather on Piso Island is just wonderful for a vacation.\nYou can sail out to watch whales, or enjoy one of the best mud springs in\nthe world. We will also show you around the island in a special car, the\nCocoon Rider. It’s our pleasure to help you enjoy your stay on Piso Island.\nFind out more about FunGana 2016 at http://www.fungana2016.com.gn.", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "8d9695f6f61b", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": null, "intro_line": "(18-20)", "child_qnums": [18, 19, 20]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-105-english-reading-passage-21", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-105-english-reading", "question_type": "reading_passage", "question_text": "(21-22)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Here is the schedule with the notice of the summer school that Tina goes to.\nDay\nTime               Mon.          Tues.           Wed.           Thurs.         Fri.\n09:30 ~ 10:30     English      Computer        English         English        Piano\n10:40 ~ 11:40      Piano        English        Painting    Dancing        Dancing\n13:30 ~ 14:30     Tennis       Painting         Tennis      Painting      Computer\n14:40 ~ 15:40     Baseball     Baseball       Swimming     Basketball Basketball\n NOTICE \n The school restaurant is closed during the summer school (7/4~7/31).\nPlease bring your own lunch. If you need to order lunch, please tell your\nclass leader the day before.\n Dancing shoes can be borrowed with your summer school card. Please\nfind Mr. Shum in Room 117.\n During the third week, the gym will be used for the High School Ball Games.\nPlease go to the playground for the basketball classes of the week.\n schedule 課表", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "8d9695f6f61b", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": null, "intro_line": "(21-22)", "child_qnums": [21, 22]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-105-english-reading-passage-23", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-105-english-reading", "question_type": "reading_passage", "question_text": "(23-24)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "The wind keeps blowing.\nThe door keeps opening.\nWill you be with me, my dear Lucy,\nWhen I look for candy\nDown there in the dark, dark kitchen?\nThe wind keeps crying.\nThe door keeps shaking.\nWill you be with me, my dear Lucy,\nWhen I pick up my toy puppy\nOut there on the high, high balcony?\nWish you could always be with me\nAnd make them go away with your Do-Re-Me.\nI remember last Halloween\nThey ran away when you started to sing,\n“ Dear Tommy, my little king,\nClose your eyes and have a sweet dream.＂\nSo please stay with me and sing\nTo stop them kicking the door, riding the wind,\nAnd pulling me down to their house under the ground.\nThey＇ ll go away if you sing here for me,\nIn a voice that gets a black cat＇\ns hair standing,\nThe strongest legs shaking, and the window glass breaking.\n(ideas from Matthew Sweeney’s poem)          poem 詩", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "8d9695f6f61b", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": null, "intro_line": "(23-24)", "child_qnums": [23, 24]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-105-english-reading-passage-25", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-105-english-reading", "question_type": "reading_passage", "question_text": "(25-27)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "\u0014                                     \u0016\n&DWFK\u0010\u0015\u0015\u0003\nE\\\u0003-RVHSK\u0003+HOOHU\n\u0015\n7KHUH\u0003ZDV\u0003D\u0003VROGLHUġ\n\u0017                                                     \u0018\n+RVSLWDO\nThis job is dangerous.\nI could die any time I fly.\n6ROGLHU                                         6ROGLHU\n\u0019                                \u001a                                         \u001b\nDoctor, how can I get out            Rule 22 – A soldier can\nThat’s easy!\nof my dangerous job?                stop flying airplanes\nonly if he is crazy. But\nhe has to MAKE THE\nDOCTOR BELIEVE IT.\n6ROGLHU       ''RFWRU\n''RFWRU                                        ''RFWRU\n''RFWRU            6ROGLHU\n\u0014\u0013\nReally? Think about it. If you are crazy,             Now people use “catch-22,”\nyou won’t worry about your life. Then you             the name of Joseph Heller’s\nbook, to mean that someone\nwould never think you should stop flying\nhas a problem like the soldier’s.\nairplanes. If you ever think you should stop\n6ROGLHU\nflying, it means that you worry about your\nlife and that you’re not crazy. If you are\nnot crazy, you have to keep flying. You see,\nyou’re caught by Rule 22. You have no way\nout. You will still need to fly.\nwant to stop              get crazy first\nBUT...\nalready              will not want\ngot crazy                to stop\n''RFWRU\n''RFWRU", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "8d9695f6f61b", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": null, "intro_line": "(25-27)", "child_qnums": [25, 26, 27]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-105-english-reading-passage-28", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-105-english-reading", "question_type": "reading_passage", "question_text": "(28-31)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Alec: So, what do you think about it?\nEllie: It’s…interesting.\nAlec: Oh, no, don’t say that.\nEllie: The first thing you should know about Olivia is that she’s scared of anything\nwith six legs. I don’t think she’ll be able to walk past the gate of Buzzing World.\nAlec: But she loves butterflies!  Well, she loved the photos of butterflies I took last\ntime I was there.\nEllie: Only when they’re not moving.\nAlec: Fine. I’ll just take her somewhere else, and that’d be OK. Right?\nEllie: Umm, you’re taking her to Wavelength for dinner?\nAlec: What’s wrong with that?!\nEllie: I wouldn’t say a dead fish is really her idea of a nice dinner, and this restaurant\nsells seafood…\nAlec: Now you’re wrong about this one.  She loved my mom’s fish balls.  She had\nseveral last time!\nEllie: OK, let’s ask someone else. Oh, there’s Lori. Hey, Lori, could you look at\nAlec’s plan? He’s taking Olivia out.\nLori: Wow! Everything’s written down on paper! Hmmm… I thought you wanted\nher to be your girlfriend.\nAlec: I do!\nLori: If you follow this plan, I’m sure it’ll be your only date with her.\n seafood 海鮮", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "8d9695f6f61b", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": null, "intro_line": "(28-31)", "child_qnums": [28, 29, 30, 31]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-105-english-reading-passage-32", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-105-english-reading", "question_type": "reading_passage", "question_text": "(32-34)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "Since the first case of “Cow Cold” was reported in Kirk State in June,\nthis killer cold has moved up north faster than we thought it would. By July,\nalmost every part of the country had been attacked by Cow Cold. In only\ntwo months, the number of dead cows has risen to 5,000. Though Cow Cold\nstarted in the south, the east of the country is the worst hit area. By this week,\n80% of the farms in Osten State have reported cases of Cow Cold.\nThe sale of milk in Osten State has slumped because of Cow Cold. Before\nCow Cold, the sale of milk in Osten State was $2.5 million each week; now it is\nless than $500,000.\nOdin State is the only area in the north without cases of Cow Cold.\nBefore we know how to deal with Cow Cold, we can only hope Odin State will\nbe lucky enough not to experience the power of this killer cold.\n(Elaine Baker, City Post)\n case 案例 area 區域", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "8d9695f6f61b", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": null, "intro_line": "(32-34)", "child_qnums": [32, 33, 34]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-105-english-reading-passage-35", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-105-english-reading", "question_type": "reading_passage", "question_text": "(35-38)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "It was 11 p.m. and Molly walked out of her bakery. She turned and looked at\nher store one last time. She wanted to remember what it 35 at the moment. A few\nhours later, people would come and clean out everything in the store. A young man\nhad bought it. He 36 it into a flower shop.\nBefore it was a bakery, this place 37 a small coffee shop. Molly worked\nin the shop as a waitress. But taking orders was never Molly’s dream; baking was.\nWhen she knew her boss planned to sell the shop, she borrowed money and bought it.\nHer bakery had been open for thirty years. Thirty very wonderful years.\nHowever, it would all come to an end tonight. Molly 38 the bakery to be a family\nbusiness. But her daughter was never interested in baking. Molly did not want her\nbusiness in a stranger’s hands, so after some serious thinking, she decided to close it.\n“Goodbye, my dear old friend,” Molly looked at the store, whispering.\n whisper 低語", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "8d9695f6f61b", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": null, "intro_line": "(35-38)", "child_qnums": [35, 36, 37, 38]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-105-english-reading-passage-39", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-105-english-reading", "question_type": "reading_passage", "question_text": "(39-41)", "options": [], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": {"passage_text": "What does the word family mean to you? An American study in 2006 showed\nthat people today 39 . Over 99% of the people who were interviewed agree that a\nhusband, a wife, and a child are a family. At the same time, 94% see a parent with a\nchild as a family, 91% say a husband and a wife, without children, are a family, and\n81% think a man and a woman, with a child, but not married, are a family too.\nThe study also found that 40 is very important in the modern thinking on family.\nThough 81% think a man and a woman, not married, with a child, are a family, the\npercentage (%) drops to 40% if the couple doesn’t have a child. This is also true with\nsame-sex couples. About 60% see two men, or two women, with a child, as a family,\nbut only 32% think so when the couple doesn’t have a child.\nIn the study, those who see two men or two women that live together as a family\noften find it OK for same-sex couples to get married.   41 . However, not everyone\nopens their arms to same-sex couples: the study said 30% have no problem seeing\npets as part of one’s family, but they do not think a same-sex couple is a family.\n couple 伴侶 same-sex 同性", "kind_hint": "single"}, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:37+00:00", "source_pdf_sha1": "8d9695f6f61b", "answer_pdf_sha1": "e4e2292682e2", "flags": [], "parse_confidence": null, "intro_line": "(39-41)", "child_qnums": [39, 40, 41]}, "is_active": true, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
